暑假小学期选了acm，学了点算法，写下来记录一下
动态规划题一	数字三角形[P1216 USACO1.5][IOI1994]数字三角形 Number Triangles - 洛谷 
用一个二维数组来储存数字金字塔：d[i][j]，i来表示行数j来表示列数。那么对于d[i][j]，d[i+1][j]就是当前数字左下方的数字，d[i+1][j+1]就是当前数字右下方的数字。

过于复杂，会超时不能AC使用递归来进行向下求和，求得到每个节点处的最大路径即可。完整代码如下：
#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;

int d[2000][2000];
int N;

int maxSum(int i,int j)&#123;
    if(i&#x3D;&#x3D;N) return d[i][j];
    int sum1&#x3D;maxSum(i+1,j);
    int sum2&#x3D;maxSum(i+1,j+1);
    if(sum1&gt;sum2) return sum1+d[i][j];
    return sum2+d[i][j];
int main()
&#123;
    cin&gt;&gt;N;
    for(int i&#x3D;1;i&lt;&#x3D;N;i++)
        for(int j&#x3D;1;j&lt;&#x3D;i;j++)
            cin&gt;&gt;d[i][j];
    cout&lt;&lt;maxSum(1,1);
    return 0;
&#125;
优化	可以AC不难发现在方法一代码运行时，重复计算的次数很多这也是导致运算超时不能AC的原因。为避免多次重复计算我们可以做如下优化：
设置一个存储到当前位置最优路径数字之和的数组Sum[i][j]，在初始化时将其数据初始化为-1以表示该点还没有计算过最优路径，当计算出到该点的最优路径时将其和存入Sum[i][j]数组内，计算下一个节点的最优路径时可以直接比较Sum[i+1][j]和Sum[i+1][j+1]的大小来确定下一步路径，减少了重复计算次数。完整代码如下：
#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;

int d[2000][2000];
int N;
int Sum[2000][2000];

int maxSum(int i,int j)&#123;
    if(i&#x3D;&#x3D;N) return d[i][j];
    if(Sum[i+1][j]&#x3D;&#x3D;-1) Sum[i+1][j]&#x3D;maxSum(i+1,j);
    if(Sum[i+1][j+1]&#x3D;&#x3D;-1) Sum[i+1][j+1]&#x3D;maxSum(i+1,j+1);
    if(Sum[i+1][j]&gt;Sum[i+1][j+1]) return Sum[i+1][j]+d[i][j];
    return Sum[i+1][j+1]+d[i][j];
&#125;

int main()
&#123;
    cin&gt;&gt;N;
    for(int i&#x3D;1;i&lt;&#x3D;N;i++)
        for(int j&#x3D;1;j&lt;&#x3D;i;j++)&#123;
            cin&gt;&gt;d[i][j];
            Sum[i][j]&#x3D;-1;
        &#125;
    cout&lt;&lt;maxSum(1,1);
    return 0;
&#125;
一个小优化	减少运行空间不影响时间复杂度在上方的优化代码中我们使用一个二维数组来存储到当前位置的最优路径的计算情况。那么我们可不可以不用再新定义一个数组，直接更改存储数字金字塔上的数组呢？显然可以，直接从下往上遍历更新最优路径的数字和到对应的位置，输出最后到顶端的最优路径数字之和即可。实际上这已经不算是递归而属于遍历比较了。

#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;

int d[2000][2000];
int N;

int main()
&#123;
    cin&gt;&gt;N;
    for(int i&#x3D;1;i&lt;&#x3D;N;i++)
        for(int j&#x3D;1;j&lt;&#x3D;i;j++)&#123;
            cin&gt;&gt;d[i][j];
        &#125;
    for(int i&#x3D;N;i&gt;1;i--)
        for(int j&#x3D;1;j&lt;i;j++)&#123;
            if(d[i][j]&gt;d[i][j+1]) d[i-1][j]&#x3D;d[i-1][j]+d[i][j];
            else d[i-1][j]&#x3D;d[i-1][j]+d[i][j+1];
        &#125;
    cout&lt;&lt;d[1][1];
    return 0;
&#125;

题二	最长上升子序列#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;

int main()
&#123;
    int a[7],b[7],n;
    cin &gt;&gt;n;
    for(int i&#x3D;0;i&lt;n;i++) &#123;cin &gt;&gt;a[i]; b[i]&#x3D;1;&#125;
    for(int i&#x3D;0;i&lt;n;i++)
        for(int j&#x3D;0;j&lt;i;j++)
            if(a[j]&lt;a[i]) b[i]&#x3D;max(b[i],b[j]+1);
    for(int i&#x3D;0;i&lt;n;i++) if(b[i]&gt;b[0]) b[0]&#x3D;b[i];
    cout&lt;&lt;b[0];
    return 0;
&#125;

题三	01背包#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;


void test_1_wei_bag_problem() &#123;
    vector&lt;int&gt; weight &#x3D; &#123;1, 3, 4&#125;;
    vector&lt;int&gt; value &#x3D; &#123;15, 20, 30&#125;;
    int bagWeight &#x3D; 4;

    vector&lt;int&gt; dp(bagWeight + 1, 0);
    for(int i &#x3D; 0; i &lt; weight.size(); i++) &#123; 
        for(int j &#x3D; bagWeight; j &gt;&#x3D; weight[i]; j--) &#123; 
            dp[j] &#x3D; max(dp[j], dp[j - weight[i]] + value[i]);
        &#125;
    &#125;
    cout &lt;&lt; dp[bagWeight] &lt;&lt; endl;
&#125;

int main() &#123;
    test_1_wei_bag_problem();
&#125;

题四	完全背包#include &lt;iostream&gt;
#define read(x,y) scanf(&quot;%d%d&quot;,&amp;x,&amp;y)

using namespace std;

const int maxn&#x3D;1010,maxv&#x3D;1010;
int v[maxn],w[maxn];
int dp[maxv];

int main() &#123;
    int N,V;
    read(N,V);
    for (int i&#x3D;1;i&lt;&#x3D;N;i++) read(v[i],w[i]);

    for (int i&#x3D;1;i&lt;&#x3D;N;i++)
        for (int j&#x3D;v[i];j&lt;&#x3D;V;j++)
            dp[j]&#x3D;max(dp[j],dp[j-v[i]]+w[i]);

    printf(&quot;%d&quot;,dp[V]);

    return 0;
&#125;

BFS迷宫#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;

struct Node
&#123;
    int row;
    int col;
&#125;;
#define MAXN 100
#define MAXM 100
int visit[MAXN][MAXM];
Node father[MAXN][MAXM];
queue&lt;Node&gt; q;
char* direction&#x3D;&quot;UDLR&quot;;  &#x2F;&#x2F; 四个方向
int dx[4] &#x3D; &#123;-1,1,0,0&#125;;	 &#x2F;&#x2F; 四个方向对应的x方向增量
int dy[4] &#x3D; &#123;0,0,-1,1 &#125;;  &#x2F;&#x2F; 四个方向对应的y方向增量
int maze[MAXN][MAXM];	&#x2F;&#x2F; 迷宫各个点是否能走
int dist[MAXN][MAXM];	&#x2F;&#x2F; 每个点到入口的最短距离
int last_dir[MAXN][MAXM];	&#x2F;&#x2F; 每个点是从其父节点的经过何种方向走到的
int ROW,COL, xs , ys,  xt , yt; &#x2F;&#x2F; 程序输入的行数、列数、开始点横纵坐标、终止点横纵坐标
void bfs(int row, int col)
&#123;
&#x2F;*从第row行第col列开始进行bfs遍历，，注意，改点为入口点*&#x2F;
    Node n;
    n.row&#x3D;row;
    n.col&#x3D;col;
    visit[row][col]&#x3D;1;	&#x2F;&#x2F; 设置已被访问
    father[row][col]&#x3D;n;	&#x2F;&#x2F; 设置父亲节点为自己
    q.push(n);
    while (!q.empty())
    &#123;
        Node front&#x3D;q.front(); &#x2F;&#x2F; 从队列头取出一个节点
        q.pop();
        &#x2F;&#x2F; 依次遍历该结点的四个方向，是否走的通
        for (int i &#x3D; 0;i &lt; 4;i++)
        &#123;
            int x&#x3D;front.row+dx[i];
            int y&#x3D; front.col + dy[i];
            &#x2F;&#x2F; 如果某个方向的一点没出界，且没访问过，并且可以走
            if (x &gt;&#x3D; 0 &amp;&amp; x&lt;ROW &amp;&amp; y &gt;&#x3D; 0 &amp;&amp; y &lt; COL &amp;&amp; !visit[x][y] &amp;&amp; maze[x][y])
            &#123;
                Node node;
                node.row&#x3D;x;
                node.col&#x3D;y;
                visit[x][y]&#x3D;1;
                father[x][y]&#x3D;front;
                dist[x][y]&#x3D;dist[front.row][front.col]+1;  &#x2F;&#x2F; 到入口最短距离为其父节点到入口最短距离+1
                last_dir[x][y]&#x3D;i;
                q.push(node); &#x2F;&#x2F; 把改点推入队列
            &#125;
        &#125;
    &#125;

&#125;

void print_path(int row, int col)
&#123;
    stack&lt;char&gt; path;		&#x2F;&#x2F; 用来保存输出路径
    &#x2F;*从第row行第col列开始往前进行路径遍历，注意，改点为出口点*&#x2F;
    while (true)
    &#123;
        int father_row &#x3D; father[row][col].row;
        int father_col &#x3D; father[row][col].col;
        &#x2F;&#x2F; 遍历的终止条件为到了入口点，还记得吗？入口点的父亲节点就是自己 &#x3D;&#x3D;&gt; Line 27
        if (father_row &#x3D;&#x3D; row &amp;&amp; father_col &#x3D;&#x3D; col)  &#x2F;&#x2F;到了入口点
        &#123;
            break;
        &#125;
        else &#x2F;&#x2F;没到入口点
        &#123;
            path.push(direction[last_dir[row][col]]); &#x2F;&#x2F; 记录该点是怎么从父亲节点过来的
            row&#x3D;father_row;
            col&#x3D;father_col;
        &#125;
    &#125;
    while (!path.empty())  &#x2F;&#x2F; 输出路径
    &#123;
        cout&lt;&lt;path.top();
        path.pop();
    &#125;
&#125;

int main()
&#123;
    cin &gt;&gt; ROW &gt;&gt; COL &gt;&gt; xs &gt;&gt; ys &gt;&gt; xt &gt;&gt; yt;
    for (int i &#x3D; 0; i &lt; ROW; i++) &#123;
        for (int j &#x3D; 0; j &lt; COL ;j++) &#123;
            cin &gt;&gt; maze[i][j];
        &#125;
    &#125;
    memset(visit, 0, sizeof(visit));
    bfs(xs,ys);
    cout &lt;&lt; endl;
    print_path(xt,yt);
    cout &lt;&lt; endl;
    return 0;
&#125;

