#include &lt;bits&#x2F;stdc++.h&gt;

#define MAX_N 100
#define MAX_M 100
using namespace std;

const int INF &#x3D; 100000000;
typedef pair&lt;int,int &gt; P;
char maze[MAX_N][MAX_M+1];
int N,M;
int sx,sy;
int gx,gy;
int d[MAX_N][MAX_M+1];
int dx[4]&#x3D;&#123;1,0,-1,0&#125;,dy[4]&#x3D;&#123;0,1,0,-1&#125;;

int bfs()
&#123;
    queue&lt;P&gt; que;
    for(int i&#x3D;0;i&lt;N;i++)
    &#123;
        for(int j&#x3D;0;j&lt;M;j++)
        &#123;
            d[i][j] &#x3D; INF;     &#x2F;&#x2F;  初始化所有点的距离为INF
        &#125;
    &#125;

    que.push(P(sx,sy));        &#x2F;&#x2F; 把起点加入队列，并设距离为 0
    d[sx][sy] &#x3D; 0;

    while(que.size())
    &#123;
        P p &#x3D; que.front(); que.pop();
        if(p.first &#x3D;&#x3D; gx &amp;&amp; p.second &#x3D;&#x3D; gy) break; &#x2F;&#x2F; 如果取出的状态是终点，则搜索结束

        for(int i&#x3D;0;i&lt;4;i++)
        &#123;
            int nx &#x3D; p.first + dx[i];
            int ny &#x3D; p.second + dy[i];

            if(0 &lt;&#x3D; nx &amp;&amp; nx &lt; N &amp;&amp; 0 &lt;&#x3D; ny &amp;&amp; ny &lt; M &amp;&amp; maze[nx][ny] !&#x3D; &#39;#&#39; &amp;&amp; d[nx][ny] &#x3D;&#x3D; INF)
            &#123;
                que.push(P(nx,ny));
                d[nx][ny] &#x3D; d[p.first][p.second] + 1;
            &#125;
        &#125;
    &#125;
    return d[gx][gy];
&#125;

int main()
&#123;
    scanf(&quot;%d%d&quot;,&amp;N,&amp;M);

    for(int i&#x3D;0;i&lt;N;i++)
        scanf(&quot;%s&quot;,maze[i]);

    for(int i&#x3D;0;i&lt;N;i++)
    &#123;
        for(int j&#x3D;0;j&lt;M;j++)
        &#123;
            if(maze[i][j]&#x3D;&#x3D;&#39;S&#39;)
            &#123;
                sx&#x3D;i;   &#x2F;&#x2F; 起点位置
                sy&#x3D;j;
            &#125;
            if(maze[i][j]&#x3D;&#x3D;&#39;G&#39;)
            &#123;
                gx&#x3D;i;   &#x2F;&#x2F; 终点位置
                gy&#x3D;j;
            &#125;
        &#125;
    &#125;
    int res &#x3D; bfs();
    printf(&quot;%d\n&quot;,res);
    return 0;
&#125;

